  const subtitleRef = useRef(null);
  const badgeRef = useRef(null);
  const iconsContainerRef = useRef(null);
  const iconRefs = useRef([]);

  const [mounted, setMounted] = useState(false);

  useEffect(() => {
    setMounted(true);
